OCR["cail-homepage.png"]="<svg xmlns=\"http://www.w3.org/2000/svg\" viewBox=\"0 0 1040 1098\" preserveAspectRatio=\"xMidYMid meet\" class=\"ocr-layer\" aria-hidden=\"true\"><g font-family=\"sans-serif\"><text x=\"24\" y=\"38.4\" font-size=\"24\" textLength=\"992\" lengthAdjust=\"spacingAndGlyphs\">CUNY AI Lab</text><text x=\"24\" y=\"75.6\" font-size=\"24\" textLength=\"992\" lengthAdjust=\"spacingAndGlyphs\">A Graduate Center Initiative</text><text x=\"24\" y=\"112.8\" font-size=\"24\" textLength=\"992\" lengthAdjust=\"spacingAndGlyphs\">AI Infrastructure for CUNY, by CUNY</text><text x=\"24\" y=\"150.0\" font-size=\"24\" textLength=\"992\" lengthAdjust=\"spacingAndGlyphs\">The CUNY AI Lab is a faculty- and staff-led initiative that develops and maintains AI tools for teaching, learning, and research.</text><text x=\"24\" y=\"187.2\" font-size=\"24\" textLength=\"992\" lengthAdjust=\"spacingAndGlyphs\">We prioritize privacy, transparency, and thoughtful integration of AI into academic work.</text><text x=\"24\" y=\"224.4\" font-size=\"24\" textLength=\"992\" lengthAdjust=\"spacingAndGlyphs\">About the Lab</text><text x=\"24\" y=\"261.6\" font-size=\"24\" textLength=\"992\" lengthAdjust=\"spacingAndGlyphs\">Explore Tools</text><text x=\"24\" y=\"298.8\" font-size=\"24\" textLength=\"992\" lengthAdjust=\"spacingAndGlyphs\">Guiding Principles</text><text x=\"24\" y=\"336.0\" font-size=\"24\" textLength=\"992\" lengthAdjust=\"spacingAndGlyphs\">Privacy by Design: We use providers that don&#x27;t retain or train on user data</text><text x=\"24\" y=\"373.2\" font-size=\"24\" textLength=\"992\" lengthAdjust=\"spacingAndGlyphs\">Transparency: We prioritize open-weight models that can be examined and understood</text><text x=\"24\" y=\"410.4\" font-size=\"24\" textLength=\"992\" lengthAdjust=\"spacingAndGlyphs\">Environmental Accountability: Tools include visibility into computational costs</text><text x=\"24\" y=\"447.6\" font-size=\"24\" textLength=\"992\" lengthAdjust=\"spacingAndGlyphs\">Criticality: AI literacy over AI dependency</text><text x=\"24\" y=\"484.8\" font-size=\"24\" textLength=\"992\" lengthAdjust=\"spacingAndGlyphs\">2026 CUNY AI Lab</text></g></svg>";
