var uid=0;
function base(s){return (s||'').split('/').pop().split('?')[0];}
function active(img){return !img.classList.contains('frag')||img.classList.contains('visible');}
function sync(img,layer){layer.classList.toggle('ocr-active',active(img));}
function text(layer){return Array.prototype.map.call(layer.querySelectorAll('text'),function(t){return t.textContent.trim();}).filter(Boolean).join(' ');}
function describe(img,layer){
 var txt=text(layer); if(!txt) return;
 var id='ocr-text-'+(++uid); var span=document.createElement('span');
 span.id=id; span.className='sr-only ocr-text'; span.textContent='Text in image: '+txt;
 img.insertAdjacentElement('afterend',span);
 var cur=(img.getAttribute('aria-describedby')||'').trim().split(/\s+/).filter(Boolean);
 if(cur.indexOf(id)<0) cur.push(id); img.setAttribute('aria-describedby',cur.join(' '));
}
function add(img){
 var fig=img.closest('figure.stage,.figure-stage,.stage'); if(!fig) return;
 var svg=OCR[base(img.getAttribute('src'))]; if(!svg) return;
 if(img.dataset.ocrLayer==='1') return;
 var d=document.createElement('div'); d.innerHTML=svg;
 var layer=d.firstElementChild; layer.classList.add('ocr-active');
 if(img.classList.contains('walk-step')) layer.classList.add('ocr-walk-step');
 if(fig.classList.contains('mkg-gallery')){
  var imgs=Array.prototype.slice.call(fig.querySelectorAll('img'));
  var i=imgs.indexOf(img); layer.classList.add('ocr-gallery-layer');
  layer.dataset.ocrIndex=String(i); layer.style.animationDelay=(i*4.5)+'s';
 }
 fig.appendChild(layer); describe(img,layer); img.dataset.ocrLayer='1';
 if(img.classList.contains('walk-step')){
  sync(img,layer);
  new MutationObserver(function(){sync(img,layer);}).observe(img,{attributes:true,attributeFilter:['class']});
 }
}
function run(){document.querySelectorAll('figure.stage img,.figure-stage img,.stage img').forEach(add);}
if(document.readyState==='loading')document.addEventListener('DOMContentLoaded',run);else run();
